-- ============================================================================
-- Plantillas de BODEGA (Compras Adelante) — desde 'PEDIDOS DE MATERIAL.xlsx'.
-- OJO: cada HOJA trae VARIAS sub-listas (con su propio título/encabezado); cada
--      sub-lista es una plantilla aparte. 17 plantillas en total.
-- tipo='bodega', sin clasificación, creadoPor='Bodega'. Idempotente.
-- Requiere la columna 'tipo' (correr antes sql/plantilla_tipo.sql).
-- ============================================================================
SET NOCOUNT ON;

-- 1) Retirar las 7 plantillas viejas (una por hoja) que juntaban mal las sub-listas.
UPDATE dbo.PlantillaSolicitud SET esEliminada = 1
 WHERE creadoPor = N'Bodega' AND esEliminada = 0
   AND nombre IN (N'FERRE', N'DISCOS', N'PVC', N'GYPSUM', N'PINTURA', N'MUEBLES', N'REPELLO');

